// Parse Claude response and extract JSON blueprint
const response = $json.content[0].text;

// Extract JSON from response (handle markdown code blocks)
let jsonStr = response;
const codeBlockMatch = response.match(/```(?:json)?\s*([\s\S]*?)```/);
if (codeBlockMatch) {
  jsonStr = codeBlockMatch[1].trim();
}

// Parse the blueprint
let blueprint;
try {
  blueprint = JSON.parse(jsonStr);
} catch (e) {
  // Try to find JSON object in text
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    blueprint = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Could not parse JSON from Claude response');
  }
}

// Create flat array of all sections with page context
const flatSections = [];
let sectionIndex = 0;

for (const page of blueprint.pages) {
  for (const section of page.sections) {
    flatSections.push({
      ...section,
      page_name: page.name,
      section_index: sectionIndex++,
      total_sections: blueprint.pages.reduce((acc, p) => acc + p.sections.length, 0),
      brand_colors: blueprint.brand_colors,
      typography: blueprint.typography,
      project_name: blueprint.project_name,
      client_name: $json.client_name,
      project_id: $json.project_id,
      global_features: blueprint.global_features || [],
      tech_stack: blueprint.tech_stack || {}
    });
  }
}

return {
  json: {
    sections: flatSections,
    blueprint: blueprint,
    total_sections: flatSections.length,
    client_name: $json.client_name,
    project_id: $json.project_id,
    project_name: blueprint.project_name
  }
};

