// Collect all section HTML responses and assemble complete index.html
const allItems = $input.all();
const firstItem = allItems[0].json;

// Extract HTML from each Claude response
const sections = allItems.map((item, idx) => {
  const response = item.json.content[0].text;
  // Extract HTML from code blocks if present
  let html = response;
  const codeBlockMatch = response.match(/```(?:html)?\s*([\s\S]*?)```/);
  if (codeBlockMatch) {
    html = codeBlockMatch[1].trim();
  }
  return {
    html: html,
    section_id: firstItem.sections[idx]?.id || `section-${idx}`,
    section_type: firstItem.sections[idx]?.type || 'generic'
  };
});

// Get brand colors from first section
const brandColors = firstItem.sections[0]?.brand_colors || {
  primary: '#6366f1',
  secondary: '#8b5cf6',
  accent: '#ec4899',
  background: '#0f0f23',
  text: '#ffffff'
};

const typography = firstItem.sections[0]?.typography || {
  heading_font: 'Inter',
  body_font: 'Inter'
};

const projectName = firstItem.project_name || 'Website';
const clientName = firstItem.client_name || 'Client';

// Assemble complete HTML document
const completeHTML = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${projectName} | ${clientName}</title>
  <meta name="description" content="${projectName} - A stunning website created by Web Factory">

  <!-- Google Fonts -->
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=${typography.heading_font.replace(/\s/g, '+')}:wght@400;500;600;700;800&family=${typography.body_font.replace(/\s/g, '+')}:wght@300;400;500;600&display=swap" rel="stylesheet">

  <!-- GSAP -->
  <script src="https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.2/gsap.min.js"></script>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.2/ScrollTrigger.min.js"></script>

  <!-- Three.js -->
  <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>

  <!-- Phosphor Icons -->
  <script src="https://unpkg.com/@phosphor-icons/web"></script>

  <style>
    :root {
      --color-primary: ${brandColors.primary};
      --color-secondary: ${brandColors.secondary};
      --color-accent: ${brandColors.accent};
      --color-bg: ${brandColors.background};
      --color-text: ${brandColors.text};
      --font-heading: '${typography.heading_font}', sans-serif;
      --font-body: '${typography.body_font}', sans-serif;
      --transition-smooth: cubic-bezier(0.4, 0, 0.2, 1);
    }

    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    html {
      scroll-behavior: smooth;
    }

    body {
      font-family: var(--font-body);
      background: var(--color-bg);
      color: var(--color-text);
      line-height: 1.6;
      overflow-x: hidden;
    }

    h1, h2, h3, h4, h5, h6 {
      font-family: var(--font-heading);
      font-weight: 700;
      line-height: 1.2;
    }

    a {
      color: var(--color-primary);
      text-decoration: none;
      transition: color 0.3s var(--transition-smooth);
    }

    a:hover {
      color: var(--color-accent);
    }

    img {
      max-width: 100%;
      height: auto;
    }

    .container {
      max-width: 1400px;
      margin: 0 auto;
      padding: 0 2rem;
    }

    @media (max-width: 768px) {
      .container {
        padding: 0 1rem;
      }
    }

    /* Scrollbar styling */
    ::-webkit-scrollbar {
      width: 8px;
    }

    ::-webkit-scrollbar-track {
      background: var(--color-bg);
    }

    ::-webkit-scrollbar-thumb {
      background: var(--color-primary);
      border-radius: 4px;
    }

    ::-webkit-scrollbar-thumb:hover {
      background: var(--color-secondary);
    }
  </style>
</head>
<body>
  ${sections.map(s => s.html).join('\n\n')}

  <script>
    // Initialize GSAP ScrollTrigger
    gsap.registerPlugin(ScrollTrigger);

    // Global smooth scroll behavior
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
      anchor.addEventListener('click', function(e) {
        e.preventDefault();
        const target = document.querySelector(this.getAttribute('href'));
        if (target) {
          target.scrollIntoView({ behavior: 'smooth' });
        }
      });
    });

    // Initialize all section animations
    document.querySelectorAll('[data-section-id]').forEach(section => {
      const sectionId = section.getAttribute('data-section-id');

      // Fade in animation
      gsap.fromTo(section, 
        { opacity: 0, y: 30 },
        {
          opacity: 1,
          y: 0,
          duration: 0.8,
          ease: 'power2.out',
          scrollTrigger: {
            trigger: section,
            start: 'top 80%',
            toggleActions: 'play none none reverse'
          }
        }
      );
    });
  </script>
</body>
</html>`;

return {
  json: {
    html: completeHTML,
    project_name: projectName,
    client_name: clientName,
    project_id: firstItem.project_id,
    total_sections: sections.length,
    repo: 'marcotrm/nexevo-3d-site'
  }
};

// Prepare file data for GitHub API
const html = $json.html;
const projectName = $json.project_name;
const clientName = $json.client_name;
const projectId = $json.project_id;

// Check if file exists (from previous node)
let sha = null;
try {
  // If the GET request succeeded, it will have a sha
  sha = $input.first().json.sha;
} catch (e) {
  // File doesn't exist, sha remains null
}

// Base64 encode the HTML
const base64Content = Buffer.from(html).toString('base64');

return {
  json: {
    content: base64Content,
    sha: sha,
    message: `🚀 Deploy ${projectName} for ${clientName} (Project: ${projectId})`,
    project_name: projectName,
    client_name: clientName,
    project_id: projectId
  }
};
